## 2.  C/‑C++ stub – `blocksci_stubs.c`

> **Important:** The file must be compiled as **C++** (`g++`/`clang++`) because it includes BlockSci’s C++ headers.  The file is named `*.c` only to keep the OCaml build system happy; the `-xc++` flag (or `cxxflags` in a `dune` stanza) tells the compiler to treat it as C++.

```c
/*--------------------------------------------------------------------
   blocksci_stubs.c – C/‑C++ glue for the BlockSci OCaml bindings
  --------------------------------------------------------------------*/

#define CAML_NAME_SPACE               /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <memory>
#include <exception>

/* ------------------------------------------------------------------
   BlockSci headers – replace the include path with whatever your
   installation uses.  The public API we need is:
     * class Chain – constructed from a directory path
     * class Block – getters: height(), hash(), timestamp(), tx_count()
     * Chain::begin() / Chain::end() returning an iterator over Block
   ------------------------------------------------------------------ */
extern "C" {
    /* Dummy forward declarations – the real headers are C++ */
}
#include "blocksci/chain.hpp"   /* <-- adjust to your installation */

/* ------------------------------------------------------------------
   OCaml custom operations for the two opaque types
   ------------------------------------------------------------------ */
static void finalize_chain(value v);
static void finalize_block(value v);

/* The custom operation structures must be static and visible to the
   GC. */
static struct custom_operations chain_custom_ops = {
    "Blocksci.chain",          /* identifier – must be unique */
    finalize_chain,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

static struct custom_operations block_custom_ops = {
    "Blocksci.block",
    finalize_block,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------
   Helper macros to retrieve the underlying C++ pointers
   ------------------------------------------------------------------ */
#define Chain_val(v)   (*((std::shared_ptr<blocksci::Chain> *) Data_custom_val(v)))
#define Block_val(v)   (*((std::shared_ptr<blocksci::Block> *) Data_custom_val(v)))

/* ------------------------------------------------------------------
   Finalisers – called by the OCaml GC when the value becomes unreachable
   ------------------------------------------------------------------ */
static void finalize_chain(value v)
{
    std::shared_ptr<blocksci::Chain> *p = (std::shared_ptr<blocksci::Chain> *) Data_custom_val(v);
    delete p;               /* shared_ptr destructor releases the chain */
}

static void finalize_block(value v)
{
    std::shared_ptr<blocksci::Block> *p = (std::shared_ptr<blocksci::Block> *) Data_custom_val(v);
    delete p;               /* shared_ptr destructor releases the block */
}

/* ------------------------------------------------------------------
   Allocation helpers – allocate an OCaml custom block that wraps a
   shared_ptr<T>.  The C++ object lives as long as the OCaml value.
   ------------------------------------------------------------------ */
static value alloc_chain(std::shared_ptr<blocksci::Chain> *ptr)
{
    value v = caml_alloc_custom(&chain_custom_ops, sizeof(std::shared_ptr<blocksci::Chain>), 0, 1);
    Chain_val(v) = *ptr;          /* copy the shared_ptr into the OCaml block */
    return v;
}

static value alloc_block(std::shared_ptr<blocksci::Block> *ptr)
{
    value v = caml_alloc_custom(&block_custom_ops, sizeof(std::shared_ptr<blocksci::Block>), 0, 1);
    Block_val(v) = *ptr;
    return v;
}

/* ------------------------------------------------------------------
   OCaml‑exposed primitives
   ------------------------------------------------------------------ */

/* open_chain : string -> chain */
CAMLprim value caml_open_chain(value path_v)
{
    CAMLparam1(path_v);
    CAMLlocal1(res);
    const char *c_path = String_val(path_v);

    /* BlockSci may throw an exception on bad path – translate it */
    try {
        std::shared_ptr<blocksci::Chain> *p = new std::shared_ptr<blocksci::Chain>(
            std::make_shared<blocksci::Chain>(c_path)
        );
        res = alloc_chain(p);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }

    CAMLreturn(res);
}

/* close_chain : chain -> unit */
CAMLprim value caml_close_chain(value chain_v)
{
    CAMLparam1(chain_v);
    /* The finaliser already releases the shared_ptr, but we make the
       operation explicit so the user can close early. */
    std::shared_ptr<blocksci::Chain> *p = (std::shared_ptr<blocksci::Chain> *) Data_custom_val(chain_v);
    delete p;                    /* destroy the shared_ptr */
    /* Overwrite the OCaml value with a dummy to avoid double free if GC
       later calls the finaliser. */
    memset(Data_custom_val(chain_v), 0, sizeof(std::shared_ptr<blocksci::Chain>));
    CAMLreturn(Val_unit);
}

/* block_height : block -> int */
CAMLprim value caml_block_height(value block_v)
{
    CAMLparam1(block_v);
    const blocksci::Block &blk = Block_val(block_v);
    CAMLreturn(Val_int(blk.height()));
}

/* block_hash : block -> string (hex) */
CAMLprim value caml_block_hash(value block_v)
{
    CAMLparam1(block_v);
    const blocksci::Block &blk = Block_val(block_v);
    std::string hex = blk.hash().to_hex();      /* assuming BlockSci provides this */
    CAMLreturn(caml_copy_string(hex.c_str()));
}

/* block_timestamp : block -> int64 */
CAMLprim value caml_block_timestamp(value block_v)
{
    CAMLparam1(block_v);
    const blocksci::Block &blk = Block_val(block_v);
    CAMLreturn(caml_copy_int64((int64_t)blk.timestamp()));
}

/* block_tx_count : block -> int */
CAMLprim value caml_block_tx_count(value block_v)
{
    CAMLparam1(block_v);
    const blocksci::Block &blk = Block_val(block_v);
    CAMLreturn(Val_int(blk.tx_count()));
}

/* iter_blocks : chain -> (block -> unit) -> unit */
CAMLprim value caml_iter_blocks(value chain_v, value cb_v)
{
    CAMLparam2(chain_v, cb_v);
    CAMLlocal1(blk_ocaml);
    /* The iterator may take a while – release the OCaml runtime lock
       while we walk the C++ collection. */
    caml_release_runtime_system();

    try {
        const std::shared_ptr<blocksci::Chain> &chain_sp = Chain_val(chain_v);
        if (!chain_sp) caml_failwith("iter_blocks: chain is closed");

        for (auto it = chain_sp->begin(); it != chain_sp->end(); ++it) {
            /* Wrap the current Block into a shared_ptr that will be owned
               by the OCaml value. */
            std::shared_ptr<blocksci::Block> *blk_sp = new std::shared_ptr<blocksci::Block>(
                std::make_shared<blocksci::Block>(*it)
            );
            blk_ocaml = alloc_block(blk_sp);   /* OCaml value now owns blk_sp */

            /* Re‑acquire the runtime before calling back into OCaml. */
            caml_acquire_runtime_system();

            /* Call the user callback.  caml_callback_exn returns either
               the result or an exception value. */
            value cb_res = caml_callback_exn(cb_v, blk_ocaml);

            if (Is_exception_result(cb_res)) {
                /* Propagate the exception – the GC will clean up the
                   block value we just allocated. */
                caml_raise(cb_res);
            }

            /* Drop the OCaml reference so the block can be reclaimed.
               The GC will run the finaliser later. */
            caml_release_runtime_system();
        }
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();   /* make sure we are in the runtime */
        caml_failwith(e.what());
    }

    caml_acquire_runtime_system();   /* make sure we exit with the lock */
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------
   Register the primitives under the OCaml module name "Blocksci"
   (the same name as the .mli file).  The generated .cmo/.cmx will be
   linked as "blocksci.cma" / "blocksci.cmxa".
   ------------------------------------------------------------------ */
static struct caml_named_value caml_named_values[] = {
    { "Blocksci.open_chain",          caml_open_chain },
    { "Blocksci.close_chain",         caml_close_chain },
    { "Blocksci.block_height",        caml_block_height },
    { "Blocksci.block_hash",          caml_block_hash },
    { "Blocksci.block_timestamp",    caml_block_timestamp },
    { "Blocksci.block_tx_count",      caml_block_tx_count },
    { "Blocksci.iter_blocks",         caml_iter_blocks },
    { NULL, NULL }
};

CAMLprim value caml_register_blocksci_primitives(value unit)
{
    CAMLparam1(unit);
    for (struct caml_named_value *p = caml_named_values; p->name != NULL; ++p) {
        caml_register_named_value(p->name, p->fn);
    }
    CAMLreturn(Val_unit);
}
```

### Explanation of the stub

| Part | What it does |
|------|--------------|
| **custom operations** (`chain_custom_ops`, `block_custom_ops`) | Give the GC a hook (`finalize_*`) that frees the underlying `std::shared_ptr`. |
| **alloc_* helpers** | Pack a `std::shared_ptr<T>` into an OCaml custom block. |
| **open_chain / close_chain** | Construct / destroy a `blocksci::Chain`. Errors from BlockSci are turned into `Failure` exceptions (`caml_failwith`). |
| **block_* accessors** | Thin wrappers that read fields from the C++ `Block` object. |
| **iter_blocks** | The heart of the binding: <br>1. Release the OCaml runtime lock (`caml_release_runtime_system`) while iterating the C++ collection (so other OCaml threads can run). <br>2. For each C++ `Block` we allocate a fresh OCaml `block` value (wrapped in a `shared_ptr`). <br>3. Re‑acquire the lock, invoke the user callback with `caml_callback_exn`. <br>4. If the callback raises, we propagate the exception and abort the loop. <br>5. The block value is left to the GC; its finaliser will delete the C++ object. |
| **caml_register_blocksci_primitives** | Optional helper you can call from an `init` function (or let the build system do it automatically).  It registers the primitives under the module name “Blocksci”. |

