## 3.  Minimal build recipe (Makefile)

```make
# --------------------------------------------------------------
#  Makefile – compile the binding and produce a library
# --------------------------------------------------------------
OCAMLFLAGS   = -thread -safe-string
CXXFLAGS     = -std=c++17 -Wall -Wextra -I$(BLOCKSCI_INC)   # <- adjust
LIBS         = -lstdc++                                 # C++ runtime

# -----------------------------------------------------------------
#  Targets
# -----------------------------------------------------------------
all: libblocksci.cmxa   # static library usable from OCaml

# 1) Compile the stub as C++ object (must use -xc++)
blocksci_stubs.o: blocksci_stubs.c
	$(CC) -xc++ $(CXXFLAGS) -c $< -o $@

# 2) Build the OCaml bytecode and native libraries
libblocksci.cma: blocksci.cmo
	ocamlc -a $^ -o $@

libblocksci.cmxa: blocksci.cmx
	ocamlopt -a $^ -o $@

# OCaml compilation of the interface (no implementation needed)
blocksci.cmi: blocksci.mli
	ocamlc -c $<

blocksci.cmo: blocksci.cmi blocksci_stubs.o
	ocamlc -c $(OCAMLFLAGS) -custom -cclib "$(LIBS)" -o $@ blocksci_stubs.o

blocksci.cmx: blocksci.cmi blocksci_stubs.o
	ocamlopt -c $(OCAMLFLAGS) -custom -cclib "$(LIBS)" -o $@ blocksci_stubs.o

clean:
	rm -f *.cm[oxai] *.o libblocksci.cmxa libblocksci.cma
```

*Replace `$(BLOCKSCI_INC)` with the directory that contains BlockSci’s headers (e.g. `/usr/local/include/blocksci`).*  
If you prefer **Dune**, the stanza is essentially the same:

```dune
(library
 (name blocksci)
 (foreign_stubs
  (language c)
  (names blocksci_stubs)
  (flags (:standard -xc++ -std=c++17))
  (libraries stdc++))
 (modules blocksci))
```

